class Trader:
    LIMIT = 10
    GAMMA = 0.4
    EXIT_OFFSET = 1_000_000_000
    CONFIG = SHOCK_CONFIG
    DRIFT_TARGET = DRIFT_TARGETS
    MODELS = REGRESSION_MODELS
    STRUCT_MODELS = {
        p: {
            "coef": v[0],
            "edge": v[1],
            "max_pos": v[2],
            "xs": [PRODUCTS[i] for i in v[3]],
        }
        for p, v in REGRESSION_MODELS.items()
    }
    PRODUCTS = PRODUCTS

    def _best_bid(self, depth):
        return max(depth.buy_orders) if depth.buy_orders else None

    def _best_ask(self, depth):
        return min(depth.sell_orders) if depth.sell_orders else None

    def _mid_price(self, depth):
        bid = self._best_bid(depth)
        ask = self._best_ask(depth)
        if bid is not None and ask is not None:
            return (bid + ask) / 2.0
        if bid is not None:
            return float(bid)
        if ask is not None:
            return float(ask)
        return None

    def _fair(self, model, mids):
        # Evaluate the OLS regression model: fair = intercept + sum(coef_i * mid_price[feature_i]).
        # Returns None if any feature price is missing - we don't trade on an incomplete signal.
        coefs, _, _, xs = model
        fair = float(coefs[0])
        for coef, idx in zip(coefs[1:], xs):
            mid = mids.get(self.PRODUCTS[idx])
            if mid is None:
                return None
            fair += float(coef) * mid
        return fair

    def _order_to_target(self, product, depth, position, target):
        target = max(-self.LIMIT, min(self.LIMIT, target))
        if target == position:
            return []
        orders = []
        if target > position:
            ask = self._best_ask(depth)
            if ask is None:
                return orders
            quantity = min(target - position, -int(depth.sell_orders[ask]), self.LIMIT - position)
            if quantity > 0:
                orders.append(Order(product, ask, quantity))
        else:
            bid = self._best_bid(depth)
            if bid is None:
                return orders
            quantity = min(position - target, int(depth.buy_orders[bid]), self.LIMIT + position)
            if quantity > 0:
                orders.append(Order(product, bid, -quantity))
        return orders

    def _take_buy(self, product, depth, fair, position, max_pos, edge):
        orders = []
        capacity = min(self.LIMIT - position, min(max_pos, self.LIMIT) - position)
        if capacity <= 0:
            return orders
        for price, volume in sorted(depth.sell_orders.items()):
            if price > fair - edge:
                break
            quantity = min(capacity, -volume)
            if quantity <= 0:
                continue
            orders.append(Order(product, price, quantity))
            capacity -= quantity
            if capacity <= 0:
                break
        return orders

    def _take_sell(self, product, depth, fair, position, max_pos, edge):
        orders = []
        target = -min(max_pos, self.LIMIT)
        capacity = min(self.LIMIT + position, position - target)
        if capacity <= 0:
            return orders
        for price, volume in sorted(depth.buy_orders.items(), reverse=True):
            if price < fair + edge:
                break
            quantity = min(capacity, volume)
            if quantity <= 0:
                continue
            orders.append(Order(product, price, -quantity))
            capacity -= quantity
            if capacity <= 0:
                break
        return orders

    def run(self, state):
        result = {}
        try:
            memory = json.loads(state.traderData) if state.traderData else {}
        except Exception:
            memory = {}

        prev_mid = memory.get("prev_mid", {})
        if state.timestamp < int(memory.get("last_ts", -1)):
            prev_mid = {}
        next_mid = dict(prev_mid)

        mids = {}
        for product, depth in state.order_depths.items():
            mid = self._mid_price(depth)
            if mid is not None:
                mids[product] = mid

        for product, depth in state.order_depths.items():
            result[product] = []
            mid = mids.get(product)
            if mid is None:
                continue

            cfg = self.CONFIG.get(product)
            position = int(state.position.get(product, 0))
            traded = False

            # Priority: shock detection > regression model > drift target.
            # Once a shock fires, we skip the model so the two signals don't conflict.
            if cfg is not None:
                mode, trigger, base_max, edge = cfg
                old_mid = prev_mid.get(product)
                if old_mid is not None:
                    move = mid - float(old_mid)
                    if abs(move) >= trigger:
                        shock_sign = 1.0 if move > 0 else -1.0
                        # revert: expect partial reversal; momentum: expect continuation.
                        expected_direction = -shock_sign if mode == "revert" else shock_sign
                        fair = mid + expected_direction * self.GAMMA * abs(move)
                        ask = self._best_ask(depth)
                        bid = self._best_bid(depth)
                        if ask is not None and fair > ask + edge:
                            result[product].extend(self._take_buy(product, depth, fair, position, base_max, edge))
                            traded = bool(result[product])
                        elif bid is not None and fair < bid - edge:
                            result[product].extend(self._take_sell(product, depth, fair, position, base_max, edge))
                            traded = bool(result[product])

            if not traded and product in self.MODELS:
                model = self.MODELS[product]
                fair = self._fair(model, mids)
                ask = self._best_ask(depth)
                bid = self._best_bid(depth)
                if fair is not None and ask is not None and bid is not None:
                    edge = float(model[1])
                    max_pos = int(model[2])
                    if ask <= fair - edge:
                        result[product].extend(self._order_to_target(product, depth, position, max_pos))
                    elif bid >= fair + edge:
                        result[product].extend(self._order_to_target(product, depth, position, -max_pos))
                    elif position > 0 and bid >= fair + self.EXIT_OFFSET:
                        result[product].extend(self._order_to_target(product, depth, position, 0))
                    elif position < 0 and ask <= fair - self.EXIT_OFFSET:
                        result[product].extend(self._order_to_target(product, depth, position, 0))

            if not result[product] and product in self.DRIFT_TARGET and product not in self.MODELS:
                result[product].extend(self._order_to_target(product, depth, position, int(self.DRIFT_TARGET[product])))

            next_mid[product] = mid

        trader_data = json.dumps({"prev_mid": next_mid, "last_ts": int(state.timestamp)}, separators=(",", ":"))
        return result, 0, trader_data

class Trader(Trader):
    EDGE_MULT = {
        "GALAXY_SOUNDS_BLACK_HOLES": 1.25,
        "GALAXY_SOUNDS_DARK_MATTER": 0.80,
        "GALAXY_SOUNDS_SOLAR_FLAMES": 1.25,
        "GALAXY_SOUNDS_SOLAR_WINDS": 1.10,
        "MICROCHIP_CIRCLE": 0.80,
        "MICROCHIP_OVAL": 1.25,
        "OXYGEN_SHAKE_MINT": 1.50,
        "PANEL_1X4": 1.25,
        "PANEL_4X4": 1.10,
        "ROBOT_IRONING": 0.65,
        "ROBOT_MOPPING": 2.00,
        "ROBOT_VACUUMING": 2.00,
        "SLEEP_POD_NYLON": 2.00,
        "SLEEP_POD_POLYESTER": 0.50,
        "SLEEP_POD_SUEDE": 1.50,
        "SNACKPACK_PISTACHIO": 0.80,
        "SNACKPACK_VANILLA": 0.80,
        "TRANSLATOR_GRAPHITE_MIST": 1.25,
        "UV_VISOR_MAGENTA": 1.50,
        "UV_VISOR_ORANGE": 0.80,
        "UV_VISOR_RED": 0.65,
        "UV_VISOR_YELLOW": 1.50,
    }
    LAG_CONFIG = {"ROBOT_DISHES": ["revert", 5, 75.0, 10]}
    MAX_LAG = 5

    def run(self, state):
        result = {}
        try:
            memory = json.loads(state.traderData) if state.traderData else {}
        except Exception:
            memory = {}

        prev_mid = memory.get("prev_mid", {})
        hist = memory.get("h", {})
        if state.timestamp < int(memory.get("last_ts", -1)):
            prev_mid = {}
            hist = {}
        next_mid = dict(prev_mid)

        mids = {}
        for product, depth in state.order_depths.items():
            mid = self._mid_price(depth)
            if mid is not None:
                mids[product] = mid

        for product, depth in state.order_depths.items():
            result[product] = []
            mid = mids.get(product)
            if mid is None:
                continue

            position = int(state.position.get(product, 0))
            traded = False

            lcfg = self.LAG_CONFIG.get(product)
            if lcfg is not None:
                mode, lag, trigger, base_max = lcfg
                h = hist.get(product, [])
                if len(h) >= lag:
                    move = mid - float(h[-lag])
                    if abs(move) >= trigger:
                        shock_sign = 1.0 if move > 0 else -1.0
                        expected_direction = shock_sign if mode == "momentum" else -shock_sign
                        fair = mid + expected_direction * self.GAMMA * abs(move)
                        ask = self._best_ask(depth)
                        bid = self._best_bid(depth)
                        if ask is not None and fair > ask:
                            result[product].extend(self._take_buy(product, depth, fair, position, base_max, 0.0))
                            traded = bool(result[product])
                        elif bid is not None and fair < bid:
                            result[product].extend(self._take_sell(product, depth, fair, position, base_max, 0.0))
                            traded = bool(result[product])

            cfg = self.CONFIG.get(product)
            if not traded and cfg is not None:
                mode, trigger, base_max, edge = cfg
                old_mid = prev_mid.get(product)
                if old_mid is not None:
                    move = mid - float(old_mid)
                    if abs(move) >= trigger:
                        shock_sign = 1.0 if move > 0 else -1.0
                        expected_direction = -shock_sign if mode == "revert" else shock_sign
                        fair = mid + expected_direction * self.GAMMA * abs(move)
                        ask = self._best_ask(depth)
                        bid = self._best_bid(depth)
                        if ask is not None and fair > ask + edge:
                            result[product].extend(self._take_buy(product, depth, fair, position, base_max, edge))
                            traded = bool(result[product])
                        elif bid is not None and fair < bid - edge:
                            result[product].extend(self._take_sell(product, depth, fair, position, base_max, edge))
                            traded = bool(result[product])

            if not traded and product in self.MODELS:
                model = self.MODELS[product]
                fair = self._fair(model, mids)
                ask = self._best_ask(depth)
                bid = self._best_bid(depth)
                if fair is not None and ask is not None and bid is not None:
                    edge = float(model[1]) * float(self.EDGE_MULT.get(product, 1.0))
                    max_pos = int(model[2])
                    if ask <= fair - edge:
                        result[product].extend(self._order_to_target(product, depth, position, max_pos))
                    elif bid >= fair + edge:
                        result[product].extend(self._order_to_target(product, depth, position, -max_pos))
                    elif position > 0 and bid >= fair + self.EXIT_OFFSET:
                        result[product].extend(self._order_to_target(product, depth, position, 0))
                    elif position < 0 and ask <= fair - self.EXIT_OFFSET:
                        result[product].extend(self._order_to_target(product, depth, position, 0))

            if not result[product] and product in self.DRIFT_TARGET and product not in self.MODELS:
                result[product].extend(self._order_to_target(product, depth, position, int(self.DRIFT_TARGET[product])))

            next_mid[product] = mid

        new_hist = {}
        for product in self.LAG_CONFIG:
            arr = list(hist.get(product, []))
            if product in mids:
                arr.append(float(mids[product]))
                if len(arr) > self.MAX_LAG:
                    arr = arr[-self.MAX_LAG:]
            if arr:
                new_hist[product] = arr

        trader_data = json.dumps({"prev_mid": next_mid, "h": new_hist, "last_ts": int(state.timestamp)}, separators=(",", ":"))
        return result, 0, trader_data

class Trader(Trader):
    GAMMA = 0.10

    CONFIG = dict(Trader.CONFIG)
    for _p in ("PEBBLES_L", "PEBBLES_M", "PEBBLES_S", "PEBBLES_XL", "PEBBLES_XS"):
        CONFIG.pop(_p, None)

    MODELS = dict(Trader.MODELS)
    for _p in ("SNACKPACK_VANILLA", "SNACKPACK_PISTACHIO"):
        MODELS.pop(_p, None)

    EDGE_MULT = dict(Trader.EDGE_MULT)

    LAG_CONFIG = {"ROBOT_DISHES": ["revert", 3, 100.0, 10]}
    MAX_LAG = 3

